html:
{%- set no_default_print_heading = 1 -%}
{%- from "templates/print_formats/standard_macros.html" import add_header -%}
{%- set currency = doc.company_currency or frappe.defaults.get_default('currency') -%}
{%- set status_label = "Draft" if doc.docstatus == 0 else "Submitted" if doc.docstatus == 1 else "Cancelled" -%}

<div class="main-container">
  {{ add_header(0, 1, doc, letter_head, no_letterhead, print_settings) }}

  <style>
  {%- set border_inset = 0 -%}
  {%- set content_inner_padding = 3 -%}

  html, body { margin:0; padding:0; height:100%; font-family: Arial, sans-serif; font-size: 13px; }

  .letter-head img,
  .letter-head .logo,
  .letter-head .logo img,
  .header-logo img,
  .company-logo img {
    max-width: 160px !important;
    max-height: 90px !important;
    width: auto !important;
    height: auto !important;
    object-fit: contain !important;
    display: inline-block !important;
  }

  .print-format {
    position: relative;
    background: transparent !important;
    margin: 0 !important;
    padding: 0;
    font-family: Arial, sans-serif;
    font-size: 13px;
  }

  .page-border {
    position: fixed;
    top: {{ border_inset }}mm;
    left: {{ border_inset }}mm;
    right: {{ border_inset }}mm;
    bottom: {{ border_inset }}mm;
    border: 1px solid #000;
    z-index: 0;
    pointer-events: none;
  }

  .main-container {
    position: relative;
    z-index: 1;
    padding: {{ content_inner_padding }}mm;
    font-family: Arial, sans-serif;
    font-size: 13px;
  }

  .print-heading,
  .print-heading + div { display: none !important; }

  .heading-label {
    font-size: 18px;
    font-weight: 600;
    text-align: center;
    color: #222;
    margin-bottom: 1px;
    letter-spacing: 1px;
    text-transform: uppercase;
    font-family: Arial, sans-serif;
  }

  .section { margin-bottom: 6px; }

  .section-title {
    font-size: 13px;
    font-weight: 600;
    border-bottom: 1px solid #000;
    color: #000;
    margin-bottom: 4px;
    padding-bottom: 1px;
    font-family: Arial, sans-serif;
  }

  .letter-head { margin-bottom: 2mm !important; }

  .info-table, .items-table, .summary-table { width: 100%; border-collapse: collapse; }

  .info-table td {
    padding: 2px 0;
    vertical-align: top;
    font-size: 13px;
    font-family: Arial, sans-serif;
  }

  .items-table th {
    background: #fff;
    color: #000;
    border-bottom: 1px solid #000;
    padding: 3px 4px;
    font-weight: 700;
    font-size: 13px;
    font-family: Arial, sans-serif;
  }

  .items-table td {
    padding: 3px 4px;
    border-bottom: none;
    vertical-align: top;
    line-height: 1.3;
    font-size: 13px;
    font-family: Arial, sans-serif;
  }

  .items-table tbody tr:nth-child(even) td {
    background: #fafafa;
  }

  .items-table tfoot td {
    border-top: 1px solid #000;
    font-weight: 700;
    padding: 3px 4px;
    font-size: 13px;
  }

  .summary-table td {
    padding: 3px 4px;
    border-bottom: 1px solid #f0f3f5;
    line-height: 1.1;
    font-size: 13px;
    font-family: Arial, sans-serif;
  }

  .grand-total td {
    border-top: 2px solid #000;
    border-bottom: 2px solid #000;
    font-weight: 700;
  }

  .sig-table { width: 100%; border-collapse: collapse; margin-top: 8px; }
  .sig-table td {
    width: 33.33%;
    padding: 6px 12px;
    vertical-align: top;
    text-align: center;
  }
  .sig-line {
    border-bottom: 1px solid #000;
    height: 28px;
    display: block;
    margin-bottom: 4px;
  }
  .sig-label {
    font-weight: 600;
    font-size: 12px;
    display: block;
    margin-bottom: 4px;
  }
  .sig-sub { font-size: 11px; color: #444; }

  .rt { text-align: right; }
  .cn { text-align: center; }
  .remark-text { font-style: italic; color: #444; font-size: 12px; }
  .party-sub { font-size: 11px; color: #555; }
  .status-badge {
    display: inline-block;
    padding: 1px 6px;
    border: 1px solid #000;
    font-size: 11px;
    font-weight: 600;
  }

  .footer-note {
    font-size: 11px;
    color: #555;
    text-align: center;
    margin-top: 8px;
    font-family: Arial, sans-serif;
    font-style: italic;
  }

  @media print {
    body { padding: 0; margin: 0; }
    .print-format { padding: 3mm; }
    .sig-table { page-break-inside: avoid; }
  }
  </style>

  <!-- Page border -->
  <div class="page-border"></div>

  <!-- Heading -->
  <div class="heading-label">{{ doc.voucher_type or "Journal Entry" }}</div>

  <!-- Voucher Details -->
  <div class="section">
    <table class="info-table">
      <tr>
        <td style="width: 50%;">
          Voucher Type: <strong>{{ doc.voucher_type or "Journal Entry" }}</strong><br>
          Prepared By: <strong>{{ doc.owner }}</strong><br>
          {% if doc.user_remark %}
          Narration: {{ doc.user_remark }}<br>
          {% endif %}
        </td>
        <td class="rt" style="width: 50%;">
          Reference No.: <strong>{{ doc.name }}</strong><br>
          Posting Date: {{ frappe.utils.formatdate(doc.posting_date, "dd-MMM-yyyy") }}<br>
          Company: {{ doc.company }}<br>
          Status: <span class="status-badge">{{ status_label }}</span>
          {% if doc.amended_from %}<br>Amended From: {{ doc.amended_from }}{% endif %}
        </td>
      </tr>
    </table>
  </div>

  <!-- Journal Entry Accounts -->
  <div class="section">
    <div class="section-title">Journal Entry Accounts</div>
    <table class="items-table">
      <thead>
        <tr>
          <th class="cn" style="width: 4%;">#</th>
          <th style="width: 30%;">Account</th>
          <th style="width: 15%;">Party</th>
          <th style="width: 12%;">Reference</th>
          <th class="rt" style="width: 12%;">Debit ({{ currency }})</th>
          <th class="rt" style="width: 12%;">Credit ({{ currency }})</th>
          <th style="width: 15%;">Remarks</th>
        </tr>
      </thead>
      <tbody>
        {% for row in doc.accounts %}
        <tr>
          <td class="cn">{{ row.idx }}</td>
          <td>
            {{ row.account }}
            {% if row.cost_center %}<br><span class="party-sub">CC: {{ row.cost_center }}</span>{% endif %}
          </td>
          <td>
            {% if row.party_type and row.party %}
              {{ row.party }}<br><span class="party-sub">{{ row.party_type }}</span>
            {% else %}-{% endif %}
          </td>
          <td>
            {% if row.reference_type and row.reference_name %}
              {{ row.reference_name }}<br><span class="party-sub">{{ row.reference_type }}</span>
            {% else %}-{% endif %}
          </td>
          <td class="rt">
            {% if row.debit_in_account_currency and row.debit_in_account_currency != 0 %}
              {{ "{:,.2f}".format(row.debit_in_account_currency) }}
            {% else %}-{% endif %}
          </td>
          <td class="rt">
            {% if row.credit_in_account_currency and row.credit_in_account_currency != 0 %}
              {{ "{:,.2f}".format(row.credit_in_account_currency) }}
            {% else %}-{% endif %}
          </td>
          <td>
            {% if row.user_remark %}
              <span class="remark-text">{{ row.user_remark }}</span>
            {% else %}-{% endif %}
          </td>
        </tr>
        {% endfor %}
      </tbody>
      <tfoot>
        <tr>
          <td colspan="4"><strong>Totals</strong></td>
          <td class="rt"><strong>{{ "{:,.2f}".format(doc.total_debit or 0) }}</strong></td>
          <td class="rt"><strong>{{ "{:,.2f}".format(doc.total_credit or 0) }}</strong></td>
          <td></td>
        </tr>
      </tfoot>
    </table>
  </div>

  <!-- Amount in Words -->
  {% if doc.total_debit %}
  <p style="margin: 4px 0 8px 0; font-size: 13px;">
    <strong>Amount in Words:</strong> {{ frappe.utils.money_in_words(doc.total_debit, currency) }}
  </p>
  {% endif %}

  <!-- Audit Trail -->
  <div class="section">
    <div class="section-title">Audit Trail</div>
    <table class="info-table">
      <tr>
        <td style="width: 50%;">
          Prepared By: <strong>{{ doc.owner }}</strong><br>
          Created On: {{ frappe.utils.formatdate(doc.creation, "dd-MMM-yyyy HH:mm") }}
        </td>
        <td style="width: 50%;">
          Last Modified By: <strong>{{ doc.modified_by }}</strong><br>
          Last Modified: {{ frappe.utils.formatdate(doc.modified, "dd-MMM-yyyy HH:mm") }}
        </td>
      </tr>
    </table>
  </div>

  <!-- Signature Block -->
  <div class="section" style="margin-top: 16px;">
    <table class="sig-table">
      <tr>
        <td>
          <span class="sig-label">Prepared By</span>
          <span class="sig-line"></span>
          <span class="sig-sub">Name &amp; Date</span>
        </td>
        <td>
          <span class="sig-label">Checked By</span>
          <span class="sig-line"></span>
          <span class="sig-sub">Name &amp; Date</span>
        </td>
        <td>
          <span class="sig-label">Approved By</span>
          <span class="sig-line"></span>
          <span class="sig-sub">Name &amp; Date</span>
        </td>
      </tr>
    </table>
  </div>

  <div class="footer-note">This is a system-generated document. Printed on {{ frappe.utils.formatdate(frappe.utils.now(), "dd-MMM-yyyy HH:mm") }}.</div>
</div>
